        #            },
        #            "metadata": {
        #                "client_order_id": "1766076671",
        #                "create_time": "1766076671243762741",
        #                "trigger": {
        #                    "trigger_type": "UNSPECIFIED",
        #                    "tpsl": {
        #                        "trigger_by": "UNSPECIFIED",
        #                        "trigger_price": "0.0",
        #                        "close_position": False
        #                    }
        #                },
        #                "broker": "UNSPECIFIED",
        #                "is_position_transfer": False,
        #                "allow_crossing": False
        #            },
        #            "state": {
        #                "status": "PENDING",
        #                "reject_reason": "UNSPECIFIED",
        #                "book_size": [
